#include <stdio.h>
#include <string.h>
#define MAX_N 200005
#define MAX_M 100005
#define MAX_LEN 100005

int N, Q;
int id[MAX_N], len[MAX_N];
char str[MAX_N][MAX_LEN];

int simulate(int *A, int size, int turn) {
    if (size == 0) return !turn;
    for (int i = 0; i < size; i++) {
        int *newA = (int *)malloc(size * sizeof(int));
        int newSize = 0;
        for (int j = 0; j < size; j++) {
            if (i != j && id[A[j]] == id[A[i]] && strncmp(str[A[j]], str[A[i]], len[A[i]]) == 0) {
                newA[newSize++] = A[j];
            }
        }
        if (simulate(newA, newSize, !turn)) return 1;
        free(newA);
    }
    return 0;
}

int main() {
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        scanf("%d %s", &id[i], str[i]);
        len[i] = strlen(str[i]);
    }
    scanf("%d", &Q);
    while (Q--) {
        int L, R, K;
        scanf("%d %d %d", &L, &R, &K);
        int A[MAX_N], size = 0;
        for (int i = 0; i < N; i++) {
            if (L <= id[i] && id[i] <= R) {
                int count = 0;
                for (int j = 0; j < N; j++) {
                    if (id[j] == id[i]) count++;
                }
                if (count <= K) A[size++] = i;
            }
        }
        int ans = 0;
        for (int i = 0; i < size; i++) {
            int *newA = (int *)malloc(size * sizeof(int));
            int newSize = 0;
            for (int j = 0; j < size; j++) {
                if (i != j && id[A[j]] != id[A[i]]) {
                    newA[newSize++] = A[j];
                }
            }
            if (simulate(newA, newSize, 0)) ans++;
            free(newA);
        }
        printf("%d\n", ans);
    }
    return 0;
}

