import java.util.Scanner;
import java.util.ArrayList;
public class Main {
    static int N, Q;
    static int[] id;
    static String[] str;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        id = new int[N];
        str = new String[N];
        for (int i = 0; i < N; i++) {
            id[i] = sc.nextInt();
            str[i] = sc.next();
        }
        Q = sc.nextInt();
        while (Q-- > 0) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int K = sc.nextInt();
            ArrayList<Integer> A = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                if (L <= id[i] && id[i] <= R) {
                    int count = 0;
                    for (int j = 0; j < N; j++) {
                        if (id[j] == id[i]) count++;
                    }
                    if (count <= K) A.add(i);
                }
            }
            int ans = 0;
            for (int i = 0; i < A.size(); i++) {
                ArrayList<Integer> newA = new ArrayList<>();
                for (int j = 0; j < A.size(); j++) {
                    if (i != j && id[A.get(j)] != id[A.get(i)]) {
                        newA.add(A.get(j));
                    }
                }
                if (simulate(newA, 0)) ans++;
            }
            System.out.println(ans);
        }
    }
    public static boolean simulate(ArrayList<Integer> A, int turn) {
        if (A.size() == 0) return turn == 0;
        for (int i = 0; i < A.size(); i++) {
            ArrayList<Integer> newA = new ArrayList<>();
            for (int j = 0; j < A.size(); j++) {
                if (i != j && id[A.get(j)] == id[A.get(i)] && str[A.get(j)].startsWith(str[A.get(i)])) {
                    newA.add(A.get(j));
                }
            }
            if (simulate(newA, turn ^ 1)) return true;
        }
        return false;
    }
}

